## Suggested Improved `app.js`

```js
'use strict';

const express = require('express');
const helmet = require('helmet');           // Security headers
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// ─── 1. Security Headers ─────────────────────────────────────────────────────
// helmet sets X-Content-Type-Options, X-Frame-Options, HSTS, CSP, etc.
app.use(helmet());

// ─── 2. Body Parsing with Size Limits ────────────────────────────────────────
// Prevents large-payload DoS attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// ─── 3. Rate Limiting ────────────────────────────────────────────────────────
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,     // Return rate limit info in `RateLimit-*` headers
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// ─── 4. Request Logging ──────────────────────────────────────────────────────
app.use((req, _res, next) => {
  const { method, url, ip } = req;
  console.log(`[${new Date().toISOString()}] ${method} ${url} from ${ip}`);
  next();
});

// ─── 5. Routes ───────────────────────────────────────────────────────────────
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Input validation: only allow safe integer for optional `limit` query param
    const rawLimit = req.query.limit;
    if (rawLimit !== undefined) {
      const limit = parseInt(rawLimit, 10);
      if (!Number.isInteger(limit) || limit < 1 || limit > 100) {
        return res.status(400).json({
          error: 'Invalid `limit` parameter. Must be an integer between 1 and 100.',
        });
      }
    }

    // In a real app, data would come from a DB; never expose internal fields
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob',   email: 'bob@example.com'   },
    ];

    res.json(users);
  } catch (err) {
    next(err); // Forward unexpected errors to the error handler
  }
});

// ─── 6. 404 Handler ──────────────────────────────────────────────────────────
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// ─── 7. Centralised Error Handler ────────────────────────────────────────────
// Must have exactly 4 parameters so Express recognises it as an error handler
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Never leak internal error details in production
  const isDev = process.env.NODE_ENV === 'development';
  console.error(`[ERROR] ${err.message}`, isDev ? err.stack : '');

  res.status(err.status || 500).json({
    error: isDev ? err.message : 'An unexpected error occurred.',
  });
});

// ─── 8. Graceful Shutdown ────────────────────────────────────────────────────
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

const shutdown = (signal) => {
  console.log(`${signal} received. Shutting down gracefully…`);
  server.close(() => {
    console.log('All connections closed. Exiting.');
    process.exit(0);
  });

  // Force-kill if connections linger for more than 10 s
  setTimeout(() => process.exit(1), 10_000).unref();
};

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT',  () => shutdown('SIGINT'));

module.exports = app;
```

