  minVersion: 'TLSv1.2',
}, app).listen(443);

// Option B (preferred for production) — reverse proxy (nginx/ALB/Cloudflare)
// Enforce via HTTPS redirect and HSTS inside the app:
app.set('trust proxy', 1);
app.use((req, res, next) => {
  if (req.headers['x-forwarded-proto'] !== 'https') {
    return res.redirect(301, `https://${req.hostname}${req.originalUrl}`);
  }
  next();
});
```

---

### P1 — Fix Within the Sprint

**3. Add Security Headers [T-04]**

```js
const helmet = require('helmet');

app.use(helmet({
  hsts: { maxAge: 31_536_000, includeSubDomains: true, preload: true },
}));
// helmet() also removes X-Powered-By automatically
```

**4. Add Rate Limiting [T-03]**

```js
const rateLimit = require('express-rate-limit');

app.use(rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 min window
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests — try again later' },
}));
```

**5. Add Custom Error Handler [T-05]**

```js
// Must be the LAST app.use() call
app.use((err, req, res, next) => {
  console.error({ err }); // internal structured log only
  res.status(err.status || 500).json({ error: 'An unexpected error occurred' });
});
```

**6. Add Explicit CORS Policy [T-08]**

```js
const cors = require('cors');
app.use(cors({
  origin: ['https://your-frontend.example.com'],
  methods: ['GET'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

---

### P2 — Address Before Production Hardening

**7. Enforce Data Minimization, Pagination & Cache-Control [T-01, T-07, T-09]**

```js
app.get('/users', authenticate, authorize('admin'), (req, res) => {
  const page  = Math.max(1,  parseInt(req.query.page,  10) || 1);
  const limit = Math.min(50, parseInt(req.query.limit, 10) || 20);
  const offset = (page - 1) * limit;

  const safeUsers = users.slice(offset, offset + limit).map(({ id, name }) => ({
    id,
    name,
    // email intentionally excluded from default projection
  }));

  res.set('Cache-Control', 'no-store, no-cache, must-revalidate, private');
  res.json({ data: safeUsers, pagination: { page, limit, total: users.length } });
});
```

**8. Add Structured Audit Logging with PII Redaction [T-06]**

```js
const pino = require('pino');
const logger = pino({
  redact: {
    paths: ['req.headers.authorization', 'req.headers.cookie', '*.email', '*.password'],
    censor: '[REDACTED]',
  },
});

app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    logger.info({
      event:      'api_access',
      method:     req.method,
      path:       req.originalUrl,
      userId:     req.user?.id ?? 'anonymous',
      sourceIp:   req.ip,
      status:     res.statusCode,
      durationMs: Date.now() - start,
    });
  });
  next();
});
```

**9. Add Request Body Limits & Catch-All 404**

```js
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// 404 catch-all — prevents leaking framework info on unknown routes
app.use((req, res) => res.status(404).json({ error: 'Not found' }));
```

**10. Strip Timestamp from `/health` [T-10]**

```js
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });  // timestamp removed
});
```

